5719 void VPlanTransforms::optimizeFindIVReductions(VPlan &Plan,
5720                                                PredicatedScalarEvolution &PSE,
5721                                                Loop &L) {
5722   ScalarEvolution &SE = *PSE.getSE();
5723   VPRegionBlock *VectorLoopRegion = Plan.getVectorLoopRegion();
5724 
5725   // Helper lambda to check if the IV range excludes the sentinel value.
5726   auto CheckSentinel = [&SE](const SCEV *IVSCEV, bool UseMax,
5727                              bool Signed) -> std::optional<APInt> {
5728     unsigned BW = IVSCEV->getType()->getScalarSizeInBits();
5729     APInt Sentinel =
5730         UseMax
5731             ? (Signed ? APInt::getSignedMinValue(BW) : APInt::getMinValue(BW))
5732             : (Signed ? APInt::getSignedMaxValue(BW) : APInt::getMaxValue(BW));
5733 
5734     ConstantRange IVRange =
5735         Signed ? SE.getSignedRange(IVSCEV) : SE.getUnsignedRange(IVSCEV);
5736     if (!IVRange.contains(Sentinel))
5737       return Sentinel;
5738     return std::nullopt;
5739   };
5740 
5741   VPValue *HeaderMask = vputils::findHeaderMask(Plan);
5742   for (VPRecipeBase &Phi :
5743        make_early_inc_range(VectorLoopRegion->getEntryBasicBlock()->phis())) {
5744     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&Phi);
5745     if (!PhiR || !RecurrenceDescriptor::isFindLastRecurrenceKind(
5746                      PhiR->getRecurrenceKind()))
5747       continue;
5748 
5749     // If there's a header mask, the backedge select will not be the find-last
5750     // select.
5751     VPValue *BackedgeVal = PhiR->getBackedgeValue();
5752     VPValue *CondSelect = BackedgeVal;
5753     if (HeaderMask &&
5754         !match(BackedgeVal, m_Select(m_Specific(HeaderMask),
5755                                      m_VPValue(CondSelect), m_Specific(PhiR))))
5756       llvm_unreachable("expected header mask select");
5757 
5758     // Get the IV from the conditional select of the reduction phi.
5759     // The conditional select should be a select between the phi and the IV.
5760     VPValue *Cond, *TrueVal, *FalseVal;
5761     if (!match(CondSelect, m_Select(m_VPValue(Cond), m_VPValue(TrueVal),
5762                                     m_VPValue(FalseVal))))
5763       continue;
5764 
5765     // The non-phi operand of the select is the IV (or expression of IV).
5766     assert(is_contained(BackedgeVal->getDefiningRecipe()->operands(), PhiR));
5767     VPValue *IV = TrueVal == PhiR ? FalseVal : TrueVal;
5768 
5769     // Check if IV is a simple expression of a widened IV.
5770     // If so, we can track the underlying IV and sink the expression.
5771     VPWidenIntOrFpInductionRecipe *ExpressionIV =
5772         getExpressionIV(IV, VectorLoopRegion);
5773     VPValue *IVToTrack = ExpressionIV ? ExpressionIV : IV;
5774 
5775     const SCEV *IVSCEV = vputils::getSCEVExprForVPValue(IVToTrack, PSE, &L);
5776     const SCEV *Step;
5777     if (!match(IVSCEV, m_scev_AffineAddRec(m_SCEV(), m_SCEV(Step))))
5778       continue;
5779 
5780     // Determine direction from SCEV step.
5781     if (!SE.isKnownNonZero(Step))
5782       continue;
5783 
5784     // Positive step means we need UMax/SMax to find the last IV value, and
5785     // UMin/SMin otherwise.
5786     bool UseMax = SE.isKnownPositive(Step);
5787     bool UseSigned = true;
5788     std::optional<APInt> SentinelVal =
5789         CheckSentinel(IVSCEV, UseMax, /*IsSigned=*/true);
5790     if (!SentinelVal) {
5791       SentinelVal = CheckSentinel(IVSCEV, UseMax, /*IsSigned=*/false);
5792       UseSigned = false;
5793     }
5794 
5795     // If no sentinel was found, fall back to a boolean AnyOf reduction to track
5796     // if the condition was ever true. Requires the IV to not wrap, otherwise we
5797     // cannot use min/max.
5798     if (!SentinelVal) {
5799       auto *AR = cast<SCEVAddRecExpr>(IVSCEV);
5800       if (AR->hasNoSignedWrap())
5801         UseSigned = true;
5802       else if (AR->hasNoUnsignedWrap())
5803         UseSigned = false;
5804       else
5805         continue;
5806     }
5807 
5808     VPInstruction *RdxResult = cast<VPInstruction>(vputils::findRecipe(
5809         BackedgeVal,
5810         match_fn(m_VPInstruction<VPInstruction::ComputeReductionResult>())));
5811 
5812     VPValue *NewBackedgeVal = CondSelect;
5813     // If IV is an expression, create a new select that tracks the underlying
5814     // IV directly and update the backedge value.
5815     if (ExpressionIV) {
5816       auto *SelectR = BackedgeVal->getDefiningRecipe();
5817       VPBuilder LoopBuilder(SelectR);
5818       NewBackedgeVal = LoopBuilder.createSelect(Cond, ExpressionIV, PhiR,
5819                                                 SelectR->getDebugLoc());
5820     }
5821 
5822     // Create the reduction result in the middle block using sentinel directly.
5823     RecurKind MinMaxKind =
5824         UseMax ? (UseSigned ? RecurKind::SMax : RecurKind::UMax)
5825                : (UseSigned ? RecurKind::SMin : RecurKind::UMin);
5826     VPIRFlags Flags(MinMaxKind, /*IsOrdered=*/false, /*IsInLoop=*/false,
5827                     FastMathFlags());
5828     DebugLoc ExitDL = RdxResult->getDebugLoc();
5829     VPBuilder MiddleBuilder(RdxResult);
5830     VPValue *ReducedIV = MiddleBuilder.createNaryOp(
5831         VPInstruction::ComputeReductionResult, NewBackedgeVal, Flags, ExitDL);
5832 
5833     VPValue *NewRdxResult;
5834     VPValue *StartVPV = PhiR->getStartValue();
5835     if (SentinelVal) {
5836       // Sentinel-based approach: reduce IVs with min/max, compare against
5837       // sentinel to detect if condition was ever true, select accordingly.
5838       VPValue *Sentinel = Plan.getConstantInt(*SentinelVal);
5839       auto *Cmp = MiddleBuilder.createICmp(CmpInst::ICMP_NE, ReducedIV,
5840                                            Sentinel, ExitDL);
5841 
5842       // If IV was an expression, sink the expression to the middle block.
5843       VPValue *ResultVal = ReducedIV;
5844       if (ExpressionIV)
5845         ResultVal =
5846             sinkBinOpToMiddleBlock(IV, ReducedIV, ExpressionIV, MiddleBuilder);
5847 
5848       NewRdxResult =
5849           MiddleBuilder.createSelect(Cmp, ResultVal, StartVPV, ExitDL);
5850       StartVPV = Sentinel;
5851     } else {
5852       // Introduce a boolean AnyOf reduction to track if the condition was ever
5853       // true in the loop. Use it to select the initial start value, if it was
5854       // never true.
5855       auto *AnyOfPhi = new VPReductionPHIRecipe(
5856           /*Phi=*/nullptr, RecurKind::Or, *Plan.getFalse(), *Plan.getFalse(),
5857           RdxUnordered{1}, {}, /*HasUsesOutsideReductionChain=*/false);
5858       AnyOfPhi->insertAfter(PhiR);
5859 
5860       VPBuilder LoopBuilder(BackedgeVal->getDefiningRecipe());
5861       VPValue *AnyOfCond = Cond;
5862       if (TrueVal == PhiR)
5863         AnyOfCond = LoopBuilder.createNot(Cond);
5864       VPValue *OrVal = LoopBuilder.createOr(AnyOfPhi, AnyOfCond);
5865       AnyOfPhi->setOperand(1, OrVal);
5866 
5867       NewRdxResult =
5868           MiddleBuilder.createNaryOp(VPInstruction::ComputeAnyOfResult,
5869                                      {StartVPV, ReducedIV, OrVal}, {}, ExitDL);
5870 
5871       // Initialize the IV reduction phi with the neutral element, not the
5872       // original start value, to ensure correct min/max reduction results.
5873       StartVPV = Plan.getOrAddLiveIn(
5874           getRecurrenceIdentity(MinMaxKind, IVSCEV->getType(), {}));
5875     }
5876     RdxResult->replaceAllUsesWith(NewRdxResult);
5877     RdxResult->eraseFromParent();
5878 
5879     auto *NewPhiR = new VPReductionPHIRecipe(
5880         cast<PHINode>(PhiR->getUnderlyingInstr()), RecurKind::FindIV, *StartVPV,
5881         *CondSelect, RdxUnordered{1}, {}, PhiR->hasUsesOutsideReductionChain());
5882     NewPhiR->insertBefore(PhiR);
5883     PhiR->replaceAllUsesWith(NewPhiR);
5884     PhiR->eraseFromParent();
5885   }
5886 }
