5584     auto *FOR = dyn_cast<VPFirstOrderRecurrencePHIRecipe>(&HeaderPhi);
5585     if (!FOR)
5586       continue;
5587 
5588     assert(VectorRegion->getSingleSuccessor() == Plan.getMiddleBlock() &&
5589            "Cannot handle loops with uncountable early exits");
5590 
5591     // This is the second phase of vectorizing first-order recurrences, creating
5592     // extract for users outside the loop. An overview of the transformation is
5593     // described below. Suppose we have the following loop with some use after
5594     // the loop of the last a[i-1],
5595     //
5596     //   for (int i = 0; i < n; ++i) {
5597     //     t = a[i - 1];
5598     //     b[i] = a[i] - t;
5599     //   }
5600     //   use t;
5601     //
5602     // There is a first-order recurrence on "a". For this loop, the shorthand
5603     // scalar IR looks like:
5604     //
5605     //   scalar.ph:
5606     //     s.init = a[-1]
5607     //     br scalar.body
5608     //
5609     //   scalar.body:
5610     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5611     //     s1 = phi [s.init, scalar.ph], [s2, scalar.body]
5612     //     s2 = a[i]
5613     //     b[i] = s2 - s1
5614     //     br cond, scalar.body, exit.block
5615     //
5616     //   exit.block:
5617     //     use = lcssa.phi [s1, scalar.body]
5618     //
5619     // In this example, s1 is a recurrence because it's value depends on the
5620     // previous iteration. In the first phase of vectorization, we created a
5621     // VPFirstOrderRecurrencePHIRecipe v1 for s1. Now we create the extracts
5622     // for users in the scalar preheader and exit block.
5623     //
5624     //   vector.ph:
5625     //     v_init = vector(..., ..., ..., a[-1])
5626     //     br vector.body
5627     //
5628     //   vector.body
5629     //     i = phi [0, vector.ph], [i+4, vector.body]
5630     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
5631     //     v2 = a[i, i+1, i+2, i+3]
5632     //     b[i] = v2 - v1
5633     //     // Next, third phase will introduce v1' = splice(v1(3), v2(0, 1, 2))
5634     //     b[i, i+1, i+2, i+3] = v2 - v1
5635     //     br cond, vector.body, middle.block
5636     //
5637     //   middle.block:
5638     //     vector.recur.extract.for.phi = v2(2)
5639     //     vector.recur.extract = v2(3)
5640     //     br cond, scalar.ph, exit.block
5641     //
5642     //   scalar.ph:
5643     //     scalar.recur.init = phi [vector.recur.extract, middle.block],
5644     //                             [s.init, otherwise]
5645     //     br scalar.body
5646     //
5647     //   scalar.body:
5648     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5649     //     s1 = phi [scalar.recur.init, scalar.ph], [s2, scalar.body]
5650     //     s2 = a[i]
5651     //     b[i] = s2 - s1
5652     //     br cond, scalar.body, exit.block
5653     //
5654     //   exit.block:
5655     //     lo = lcssa.phi [s1, scalar.body],
5656     //                    [vector.recur.extract.for.phi, middle.block]
5657     //
5658     // Now update VPIRInstructions modeling LCSSA phis in the exit block.
5659     // Extract the penultimate value of the recurrence and use it as operand for
5660     // the VPIRInstruction modeling the phi.
5661     for (VPRecipeBase &R : make_early_inc_range(
5662              make_range(MiddleVPBB->getFirstNonPhi(), MiddleVPBB->end()))) {
5663       if (!match(&R, m_ExtractLastLaneOfLastPart(m_Specific(FOR))))
5664         continue;
5665 
5666       // For VF vscale x 1, if vscale = 1, we are unable to extract the
5667       // penultimate value of the recurrence. Instead we rely on the existing
5668       // extract of the last element from the result of
5669       // VPInstruction::FirstOrderRecurrenceSplice.
5670       // TODO: Consider vscale_range info and UF.
5671       if (LoopVectorizationPlanner::getDecisionAndClampRange(IsScalableOne,
5672                                                              Range))
5673         return;
5674       VPValue *PenultimateElement = MiddleBuilder.createNaryOp(
5675           VPInstruction::ExtractPenultimateElement, FOR->getBackedgeValue(), {},
5676           "vector.recur.extract.for.phi");
5677       cast<VPInstruction>(&R)->replaceAllUsesWith(PenultimateElement);
5678     }
5679   }
