5909 static VPSingleDefRecipe *
5910 optimizeExtendsForPartialReduction(VPSingleDefRecipe *BinOp,
5911                                    VPTypeAnalysis &TypeInfo) {
5912   // reduce.add(mul(ext(A), C))
5913   // -> reduce.add(mul(ext(A), ext(trunc(C))))
5914   const APInt *Const;
5915   if (match(BinOp, m_Mul(m_ZExtOrSExt(m_VPValue()), m_APInt(Const)))) {
5916     auto *ExtA = cast<VPWidenCastRecipe>(BinOp->getOperand(0));
5917     Instruction::CastOps ExtOpc = ExtA->getOpcode();
5918     Type *NarrowTy = TypeInfo.inferScalarType(ExtA->getOperand(0));
5919     if (!BinOp->hasOneUse() ||
5920         !llvm::canConstantBeExtended(
5921             Const, NarrowTy, TTI::getPartialReductionExtendKind(ExtOpc)))
5922       return BinOp;
5923 
5924     VPBuilder Builder(BinOp);
5925     auto *Trunc = Builder.createWidenCast(Instruction::CastOps::Trunc,
5926                                           BinOp->getOperand(1), NarrowTy);
5927     Type *WideTy = TypeInfo.inferScalarType(ExtA);
5928     BinOp->setOperand(1, Builder.createWidenCast(ExtOpc, Trunc, WideTy));
5929     return BinOp;
5930   }
5931 
5932   // reduce.add(ext(mul(ext(A), ext(B))))
5933   // -> reduce.add(mul(wider_ext(A), wider_ext(B)))
5934   if (match(BinOp, m_ZExtOrSExt(m_Mul(m_ZExtOrSExt(m_VPValue()),
5935                                       m_ZExtOrSExt(m_VPValue()))))) {
5936     auto *Ext = cast<VPWidenCastRecipe>(BinOp);
5937     auto *Mul = cast<VPWidenRecipe>(Ext->getOperand(0));
5938     auto *MulLHS = cast<VPWidenCastRecipe>(Mul->getOperand(0));
5939     auto *MulRHS = cast<VPWidenCastRecipe>(Mul->getOperand(1));
5940     if (!Mul->hasOneUse() ||
5941         (Ext->getOpcode() != MulLHS->getOpcode() && MulLHS != MulRHS) ||
5942         MulLHS->getOpcode() != MulRHS->getOpcode())
5943       return BinOp;
5944     VPBuilder Builder(Mul);
5945     Mul->setOperand(0, Builder.createWidenCast(MulLHS->getOpcode(),
5946                                                MulLHS->getOperand(0),
5947                                                Ext->getResultType()));
5948     Mul->setOperand(1, MulLHS == MulRHS
5949                            ? Mul->getOperand(0)
5950                            : Builder.createWidenCast(MulRHS->getOpcode(),
5951                                                      MulRHS->getOperand(0),
5952                                                      Ext->getResultType()));
5953     return Mul;
5954   }
5955 
5956   return BinOp;
5957 }
