5959 // Helper to transform a partial reduction chain into a partial reduction
5960 // recipe. Assumes profitability has been checked.
5961 static void transformToPartialReduction(const VPPartialReductionChain &Chain,
5962                                         VPTypeAnalysis &TypeInfo, VPlan &Plan,
5963                                         VPReductionPHIRecipe *RdxPhi) {
5964   VPWidenRecipe *WidenRecipe = Chain.ReductionBinOp;
5965   assert(WidenRecipe->getNumOperands() == 2 && "Expected binary operation");
5966 
5967   VPValue *BinOpVal = WidenRecipe->getOperand(0);
5968   VPValue *Accumulator = WidenRecipe->getOperand(1);
5969 
5970   // Swap if needed to ensure Accumulator is the PHI or partial reduction.
5971   if (isa<VPReductionPHIRecipe, VPReductionRecipe>(BinOpVal) ||
5972       isa<VPExpressionRecipe>(BinOpVal))
5973     std::swap(BinOpVal, Accumulator);
5974   auto *BinOp = cast<VPSingleDefRecipe>(BinOpVal->getDefiningRecipe());
5975 
5976   // Sub-reductions can be implemented in two ways:
5977   // (1) negate the operand in the vector loop (the default way).
5978   // (2) subtract the reduced value from the init value in the middle block.
5979   // Both ways keep the reduction itself as an 'add' reduction.
5980   //
5981   // The ISD nodes for partial reductions don't support folding the
5982   // sub/negation into its operands because the following is not a valid
5983   // transformation:
5984   //      sub(0, mul(ext(a), ext(b)))
5985   //   -> mul(ext(a), ext(sub(0, b)))
5986   //
5987   // It's therefore better to choose option (2) such that the partial
5988   // reduction is always positive (starting at '0') and to do a final
5989   // subtract in the middle block.
5990   if (WidenRecipe->getOpcode() == Instruction::Sub &&
5991       Chain.RK != RecurKind::Sub) {
5992     VPBuilder Builder(WidenRecipe);
5993     Type *ElemTy = TypeInfo.inferScalarType(BinOp);
5994     auto *Zero = Plan.getConstantInt(ElemTy, 0);
5995     VPIRFlags Flags = WidenRecipe->getUnderlyingInstr()
5996                           ? VPIRFlags(*WidenRecipe->getUnderlyingInstr())
5997                           : VPIRFlags();
5998     auto *NegRecipe = new VPWidenRecipe(Instruction::Sub, {Zero, BinOp}, Flags,
5999                                         VPIRMetadata(), DebugLoc::getUnknown());
6000     Builder.insert(NegRecipe);
6001     BinOp = NegRecipe;
6002   }
6003 
6004   // FIXME: Do these transforms before invoking the cost-model.
6005   BinOp = optimizeExtendsForPartialReduction(BinOp, TypeInfo);
6006 
6007   // Check if WidenRecipe is the final result of the reduction. If so look
6008   // through selects for predicated reductions.
6009   VPValue *Cond = nullptr;
6010   VPValue *ExitValue = cast_or_null<VPInstruction>(vputils::findUserOf(
6011       WidenRecipe,
6012       m_Select(m_VPValue(Cond), m_Specific(WidenRecipe), m_Specific(RdxPhi))));
6013   bool IsLastInChain = RdxPhi->getBackedgeValue() == WidenRecipe ||
6014                        RdxPhi->getBackedgeValue() == ExitValue;
6015   assert((!ExitValue || IsLastInChain) &&
6016          "if we found ExitValue, it must match RdxPhi's backedge value");
6017 
6018   Type *PhiType = TypeInfo.inferScalarType(RdxPhi);
6019   RecurKind RdxKind =
6020       PhiType->isFloatingPointTy() ? RecurKind::FAdd : RecurKind::Add;
6021   auto *PartialRed = new VPReductionRecipe(
6022       RdxKind,
6023       RdxKind == RecurKind::FAdd ? WidenRecipe->getFastMathFlags()
6024                                  : FastMathFlags(),
6025       WidenRecipe->getUnderlyingInstr(), Accumulator, BinOp, Cond,
6026       RdxUnordered{/*VFScaleFactor=*/Chain.ScaleFactor});
6027   PartialRed->insertBefore(WidenRecipe);
6028 
6029   if (Cond)
6030     ExitValue->replaceAllUsesWith(PartialRed);
6031   WidenRecipe->replaceAllUsesWith(PartialRed);
6032 
6033   // We only need to update the PHI node once, which is when we find the
6034   // last reduction in the chain.
6035   if (!IsLastInChain)
6036     return;
6037 
6038   // Scale the PHI and ReductionStartVector by the VFScaleFactor
6039   assert(RdxPhi->getVFScaleFactor() == 1 && "scale factor must not be set");
6040   RdxPhi->setVFScaleFactor(Chain.ScaleFactor);
6041 
6042   auto *StartInst = cast<VPInstruction>(RdxPhi->getStartValue());
6043   assert(StartInst->getOpcode() == VPInstruction::ReductionStartVector);
6044   auto *NewScaleFactor = Plan.getConstantInt(32, Chain.ScaleFactor);
6045   StartInst->setOperand(2, NewScaleFactor);
6046 
6047   // If this is the last value in a sub-reduction chain, then update the PHI
6048   // node to start at `0` and update the reduction-result to subtract from
6049   // the PHI's start value.
