5682 /// Check if \p V is a binary expression of a widened IV and a loop-invariant
5683 /// value. Returns the widened IV if found, nullptr otherwise.
5684 static VPWidenIntOrFpInductionRecipe *
5685 getExpressionIV(VPValue *V, VPRegionBlock *VectorLoopRegion) {
5686   auto *BinOp = dyn_cast<VPWidenRecipe>(V);
5687   if (!BinOp || !Instruction::isBinaryOp(BinOp->getOpcode()))
5688     return nullptr;
5689 
5690   VPWidenIntOrFpInductionRecipe *WideIV = nullptr;
5691   for (VPValue *Op : BinOp->operands()) {
5692     // Operands must be a single IV and others must be loop invariant.
5693     auto *Cand = dyn_cast<VPWidenIntOrFpInductionRecipe>(Op);
5694     if (Cand) {
5695       if (WideIV)
5696         return nullptr;
5697       WideIV = Cand;
5698       continue;
5699     }
5700     if (!Op->isDefinedOutsideLoopRegions())
5701       return nullptr;
5702   }
5703   return WideIV;
5704 }
