5706 /// Create a scalar version of the binary op \p V in the middle block,
5707 /// replacing \p WidenIV with \p ScalarIV.
5708 static VPValue *sinkBinOpToMiddleBlock(VPValue *V, VPValue *ScalarIV,
5709                                        VPWidenIntOrFpInductionRecipe *WidenIV,
5710                                        VPBuilder &Builder) {
5711   auto *BinOp = cast<VPWidenRecipe>(V->getDefiningRecipe());
5712   auto Ops = to_vector(map_range(BinOp->operands(), [&](VPValue *Op) {
5713     return Op == WidenIV ? ScalarIV : Op;
5714   }));
5715   return Builder.createNaryOp(BinOp->getOpcode(), Ops, VPIRFlags(*BinOp),
5716                               BinOp->getDebugLoc());
